+    errors.push('Worker name must be lowercase alphanumeric with hyphens');
+  }
+
+  if (!def.description) {
+    errors.push('Worker description is required');
+  }
+
+  if (!def.phases || def.phases.length === 0) {
+    errors.push('At least one phase is required');
