+  capabilities: CapabilityConfig;
+  /** Merged file filter */
+  fileFilter: FileFilterConfig;
+  /** Merged output config */
+  output: OutputConfig;
+  /** Execute the worker */
+  execute: (context: WorkerContext) => Promise<WorkerResults>;
+}
