+    defaultCapabilities?: Partial<CapabilityConfig>;
+    defaultFileFilter?: Partial<FileFilterConfig>;
+    defaultOutput?: Partial<OutputConfig>;
+  }
+): CustomWorkerInstance {
+  // Validate definition
+  const validation = validateWorkerDefinition(definition);
