+
+    const detector = getTriggerDetector();
+    const triggers = detector.detect(prompt);
+
+    return {
+      success: true,
+      hasTriggers: triggers.length > 0,
+      triggers: triggers.map(t => ({
+        keyword: t.keyword,
+        topic: t.topic,
+        priority: t.config.priority
+      }))
