+  /**
+   * Get slot availability info
+   */
+  getAvailability(): {
+    totalSlots: number;
+    usedSlots: number;
+    availableSlots: number;
+    byTrigger: Record<string, { used: number; max: number }>;
+  } {
+    const stats = this.getStats();
+    const byTrigger: Record<string, { used: number; max: number }> = {};
