+    { max: 5, label: '1-5ms' },
+    { max: 10, label: '5-10ms' },
+    { max: 50, label: '10-50ms' },
+    { max: 100, label: '50-100ms' },
+    { max: 500, label: '100-500ms' },
+    { max: 1000, label: '500ms-1s' },
+    { max: Infinity, label: '>1s' }
+  ];
