+  for (const latency of latencies) {
+    for (let i = 0; i < buckets.length; i++) {
+      if (latency <= buckets[i].max) {
+        counts[i]++;
+        break;
+      }
+    }
+  }
+
+  return buckets.map((bucket, i) => ({
+    range: bucket.label,
+    count: counts[i],
+    percentage: (counts[i] / latencies.length) * 100
