+// Database interface for both backends
+interface DbWrapper {
+  run(sql: string, params?: any[]): void;
+  get<T>(sql: string, params?: any[]): T | undefined;
+  all<T>(sql: string, params?: any[]): T[];
+  exec(sql: string): void;
+  pragma(directive: string): void;
+  prepare(sql: string): {
+    run(...params: any[]): any;
+    get(...params: any[]): any;
+    all(...params: any[]): any[];
+  };
+  close(): void;
+}
+
+// Create wrapper for better-sqlite3
+function createBetterSqliteWrapper(db: any): DbWrapper {
+  return {
+    run: (sql, params) => db.prepare(sql).run(...(params || [])),
+    get: (sql, params) => db.prepare(sql).get(...(params || [])),
+    all: (sql, params) => db.prepare(sql).all(...(params || [])),
+    exec: (sql) => db.exec(sql),
+    pragma: (directive) => db.pragma(directive),
+    prepare: (sql) => db.prepare(sql),
+    close: () => db.close()
+  };
+}
+
+// Create wrapper for sql.js
+function createSqlJsWrapper(db: any, dbPath: string): DbWrapper {
+  // sql.js needs manual save
+  const saveDb = () => {
+    try {
+      const data = db.export();
+      const buffer = Buffer.from(data);
+      fs.writeFileSync(dbPath, buffer);
+    } catch { /* ignore save errors */ }
+  };
+
+  return {
+    run: (sql, params) => {
+      db.run(sql, params);
+      saveDb();
+    },
+    get: (sql, params) => {
+      const stmt = db.prepare(sql);
+      stmt.bind(params);
+      if (stmt.step()) {
+        const row = stmt.getAsObject();
+        stmt.free();
+        return row;
+      }
+      stmt.free();
+      return undefined;
+    },
+    all: (sql, params) => {
+      const results: any[] = [];
+      const stmt = db.prepare(sql);
+      if (params) stmt.bind(params);
+      while (stmt.step()) {
+        results.push(stmt.getAsObject());
+      }
+      stmt.free();
+      return results;
+    },
+    exec: (sql) => {
+      db.exec(sql);
+      saveDb();
+    },
+    pragma: () => { /* sql.js doesn't support all pragmas */ },
+    prepare: (sql) => {
+      const stmt = db.prepare(sql);
